#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
struct matrix
{
    int a[4][4];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    void clear()
    {
        (*this)=matrix();
    }
    void init()
    {
        a[0][0]=a[1][1]=a[2][2]=a[3][3]=1;
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=0;i<4;i++)
        {
            for(long long j=0;j<4;j++)
            {
                c.a[i][j]+=1ll*a.a[i][0]*b.a[0][j]%mod;
                c.a[i][j]=(c.a[i][j]>=mod?(c.a[i][j]-mod):c.a[i][j]);
                c.a[i][j]+=1ll*a.a[i][1]*b.a[1][j]%mod;
                c.a[i][j]=(c.a[i][j]>=mod?(c.a[i][j]-mod):c.a[i][j]);
                c.a[i][j]+=1ll*a.a[i][2]*b.a[2][j]%mod;
                c.a[i][j]=(c.a[i][j]>=mod?(c.a[i][j]-mod):c.a[i][j]);
                c.a[i][j]+=1ll*a.a[i][3]*b.a[3][j]%mod;
                c.a[i][j]=(c.a[i][j]>=mod?(c.a[i][j]-mod):c.a[i][j]);
            }
        }
        return c;
    }
    friend void operator*=(matrix &a,const matrix &b)
    {
        a=a*b;
    }
    friend matrix operator+(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=0;i<4;i++)
        {
            for(long long j=0;j<4;j++)
            {
                c.a[i][j]=(a.a[i][j]+b.a[i][j]);
                c.a[i][j]=(c.a[i][j]>=mod?c.a[i][j]-mod:c.a[i][j]);
            }
        }
        return c;
    }
    friend void operator+=(matrix &a,const matrix &b)
    {
        a=a+b;
    }
}a[300010],A[4],B[4];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        matrix tag,sum;
    }a[750010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
    }
    void pushdown(long long x)
    {
        long long ls=a[x].lson,rs=a[x].rson;
        a[ls].sum*=a[x].tag;
        a[rs].sum*=a[x].tag;
        a[ls].tag*=a[x].tag;
        a[rs].tag*=a[x].tag;
        a[x].tag.clear();
        a[x].tag.init();
    }
    long long init(matrix b[],long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].tag.clear();
        a[x].tag.init();
        if(l==r)
        {
            a[x].sum=b[l];
            return x;
        }
        a[x].lson=init(b,l,mid);
        a[x].rson=init(b,mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,matrix z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].sum*=z;
            a[x].tag*=z;
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,z);
        update(a[x].rson,l,r,z);
        pushup(x);
    }
    matrix query(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return matrix();
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (query(a[x].lson,l,r)+query(a[x].rson,l,r));
    }
}t;
int main()
{
    A[0].init();
    A[1].init();
    A[2].init();
    B[0].init();
    B[1].init();
    B[2].init();
    A[0].a[1][0]=A[1].a[2][1]=A[2].a[0][2]=1;
    B[2].a[2][2]=0;
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&a[i].a[0][0],&a[i].a[0][1],&a[i].a[0][2]);
        a[i].a[0][3]=1;
    }
    t.init(a,1,n);
    int m;
    scanf("%d",&m);
    while(m--)
    {
        int op,l,r;
        scanf("%d%d%d",&op,&l,&r);
        if(op<=3)
        {
            t.update(1,l,r,A[op-1]);
        }
        else if(op<=6)
        {
            int x;
            scanf("%d",&x);
            B[0].a[3][0]=B[1].a[1][1]=B[2].a[3][2]=x;
            t.update(1,l,r,B[op-4]);
        }
        else
        {
            matrix ans=t.query(1,l,r);
            printf("%d %d %d\n",ans.a[0][0],ans.a[0][1],ans.a[0][2]);
        }
    }
    return 0;
}
